package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.MalformedJsonException;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonParserTest {

    @Test
    public void testParseReader_validJson_consumesEntireDocument() throws Exception {
        String json = "{\"key\":\"value\"}";
        Reader reader = new StringReader(json);

        JsonElement result = JsonParser.parseReader(reader);

        assertNotNull(result);
        assertFalse(result.isJsonNull());
    }

    @Test
    public void testParseReader_emptyJson_returnsJsonNull() throws Exception {
        String json = "null";
        Reader reader = new StringReader(json);

        JsonElement result = JsonParser.parseReader(reader);

        assertNotNull(result);
        assertTrue(result.isJsonNull());
    }

    @Test
    public void testParseReader_extraTokens_throwsJsonSyntaxException() throws Exception {
        String json = "{\"key\":\"value\"} extra";
        Reader reader = new StringReader(json);

        JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> JsonParser.parseReader(reader));
        assertEquals("Did not consume the entire document.", thrown.getMessage());
    }

    @Test
    public void testParseReader_malformedJson_throwsJsonSyntaxException() throws Exception {
        Reader reader = mock(Reader.class);
        JsonReader jsonReader = mock(JsonReader.class);

        // Use reflection to invoke private static parseReader(JsonReader) and mock it to throw MalformedJsonException
        Method parseReaderMethod = JsonParser.class.getDeclaredMethod("parseReader", JsonReader.class);
        parseReaderMethod.setAccessible(true);

        // Spy JsonParser class to mock static method parseReader(JsonReader)
        // Since static mocking requires Mockito inline or other, we'll simulate by subclassing

        JsonParser parserSpy = new JsonParser() {
            public JsonElement parseReader(JsonReader r) throws IOException {
                throw new MalformedJsonException("Malformed JSON");
            }
        };

        // Instead of mocking static, we test parseReader(Reader) with a Reader that causes MalformedJsonException
        // So we mock JsonReader constructor to throw MalformedJsonException using a custom Reader that triggers it

        Reader badReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                throw new MalformedJsonException("Malformed JSON");
            }
            @Override
            public void close() throws IOException { }
        };

        JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> JsonParser.parseReader(badReader));
        assertNotNull(thrown.getCause());
        assertTrue(thrown.getCause() instanceof MalformedJsonException);
    }

    @Test
    public void testParseReader_ioException_throwsJsonIOException() {
        Reader badReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                throw new IOException("IO error");
            }
            @Override
            public void close() throws IOException { }
        };

        JsonIOException thrown = assertThrows(JsonIOException.class, () -> JsonParser.parseReader(badReader));
        assertNotNull(thrown.getCause());
        assertTrue(thrown.getCause() instanceof IOException);
    }

    @Test
    public void testParseReader_numberFormatException_throwsJsonSyntaxException() throws Exception {
        // We need to simulate parseReader(JsonReader) throwing NumberFormatException
        // Use reflection to invoke private static parseReader(JsonReader) and simulate throwing NumberFormatException
        // Since parseReader(JsonReader) is static and package private, we invoke it via reflection on a mock JsonReader

        JsonReader jsonReader = mock(JsonReader.class);

        Method parseReaderMethod = JsonParser.class.getDeclaredMethod("parseReader", JsonReader.class);
        parseReaderMethod.setAccessible(true);

        // We cannot override static method behavior with Mockito 3 without inline mock maker
        // Instead, test parseReader(Reader) by passing a Reader that causes NumberFormatException during parsing

        Reader reader = new Reader() {
            private boolean firstCall = true;

            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                if (firstCall) {
                    firstCall = false;
                    // Provide JSON that will cause NumberFormatException during parsing
                    String badNumberJson = "1.2.3";
                    int length = Math.min(len, badNumberJson.length());
                    badNumberJson.getChars(0, length, cbuf, off);
                    return length;
                }
                return -1;
            }
            @Override
            public void close() throws IOException { }
        };

        JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> JsonParser.parseReader(reader));
        assertNotNull(thrown.getCause());
        assertTrue(thrown.getCause() instanceof NumberFormatException);
    }
}
